// 지난 7일 게시물 필터링 + 성과 분석
const account = $('IG 계정 정보 조회').first().json;
const mediaResp = $input.first().json;

// 에러 체크
if (!mediaResp.data || mediaResp.error) {
  return [{ json: {
    error: true,
    message: mediaResp.error?.message || 'Instagram API 응답 오류. 토큰을 확인하세요.',
    accountInfo: account
  }}];
}

const now = new Date();
const weekAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);

// 7일 이내 게시물만 필터
const recentMedia = mediaResp.data.filter(m => {
  const ts = new Date(m.timestamp);
  return ts >= weekAgo;
});

// 참여도 계산 (좋아요 + 댓글)
const analyzed = recentMedia.map(m => ({
  id: m.id,
  caption: (m.caption || '').substring(0, 50),
  type: m.media_type,
  likes: m.like_count || 0,
  comments: m.comments_count || 0,
  engagement: (m.like_count || 0) + (m.comments_count || 0),
  permalink: m.permalink,
  timestamp: m.timestamp,
  date: new Date(m.timestamp).toLocaleDateString('ko-KR')
}));

// 참여도 내림차순 정렬
analyzed.sort((a, b) => b.engagement - a.engagement);

// 총합 계산
const totalLikes = analyzed.reduce((s, m) => s + m.likes, 0);
const totalComments = analyzed.reduce((s, m) => s + m.comments, 0);
const totalEngagement = totalLikes + totalComments;

// 미디어 타입별 카운트
const typeCount = {};
analyzed.forEach(m => {
  typeCount[m.type] = (typeCount[m.type] || 0) + 1;
});

const best3 = analyzed.slice(0, 3);
const worst3 = analyzed.length > 3 ? analyzed.slice(-3).reverse() : [];

return [{ json: {
  error: false,
  account: {
    username: account.username || 'unknown',
    followers: account.followers_count || 0,
    totalMedia: account.media_count || 0
  },
  weekSummary: {
    postCount: analyzed.length,
    totalLikes,
    totalComments,
    totalEngagement,
    avgEngagement: analyzed.length > 0 ? Math.round(totalEngagement / analyzed.length) : 0,
    typeBreakdown: typeCount
  },
  best3,
  worst3,
  period: {
    from: weekAgo.toLocaleDateString('ko-KR'),
    to: now.toLocaleDateString('ko-KR')
  }
}}];

// 에러 발생 시 알림 메시지
const data = $input.first().json;
const msg = `⚠️ *인스타그램 주간 리포트 오류*

\`\`\`
$\{data.message}
\`\`\`

토큰 만료 또는 권한 부족일 수 있습니다.
관리자에게 확인하세요.`;

return [{ json: { message: msg } }];

// 성공 리포트 생성
const d = $input.first().json;
const a = d.account;
const s = d.weekSummary;

let typeStr = '';
if (s.typeBreakdown) {
  const labels = { IMAGE: '사진', VIDEO: '영상', CAROUSEL_ALBUM: '캐러셀', REELS: '릴스' };
  typeStr = Object.entries(s.typeBreakdown)
    .map(([k, v]) => `  $\{labels[k] || k}: $\{v}건`)
    .join('\n');
}

let bestStr = '';
if (d.best3 && d.best3.length > 0) {
  bestStr = d.best3.map((m, i) => {
    const cap = m.caption ? m.caption.replace(/\n/g, ' ') : '(캡션 없음)';
    return `  $\{i + 1}. ❤️$\{m.likes} 💬$\{m.comments} | $\{cap}...`;
  }).join('\n');
}

let worstStr = '';
if (d.worst3 && d.worst3.length > 0) {
  worstStr = d.worst3.map((m, i) => {
    const cap = m.caption ? m.caption.replace(/\n/g, ' ') : '(캡션 없음)';
    return `  $\{i + 1}. ❤️$\{m.likes} 💬$\{m.comments} | $\{cap}...`;
  }).join('\n');
}

const msg = `📊 *인스타그램 주간 리포트*\n$\{d.period.from} ~ $\{d.period.to}\n\n` +
  `👤 @$\{a.username} | 팔로워 $\{a.followers?.toLocaleString()}명\n\n` +
  `📌 *이번 주 요약*\n` +
  `  게시물: $\{s.postCount}건\n` +
  `  총 좋아요: $\{s.totalLikes}\n` +
  `  총 댓글: $\{s.totalComments}\n` +
  `  평균 참여: $\{s.avgEngagement}/게시물\n\n` +
  (typeStr ? `📂 *유형별*\n$\{typeStr}\n\n` : '') +
  (bestStr ? `🏆 *베스트 TOP 3*\n$\{bestStr}\n\n` : '') +
  (worstStr ? `📉 *개선 필요 3건*\n$\{worstStr}\n\n` : '') +
  `💡 베스트 게시물의 공통점을 분석하여\n다음 주 콘텐츠 전략에 반영하세요.`;

return [{ json: { message: msg } }];
